"use strict";(self.webpackChunkpurpl_brain_docs=self.webpackChunkpurpl_brain_docs||[]).push([[278],{8286:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>c,contentTitle:()=>r,default:()=>l,frontMatter:()=>o,metadata:()=>a,toc:()=>h});const a=JSON.parse('{"id":"why/bet","title":"The Strategic Bet","description":"Agent cooperation vs. automatic interception","source":"@site/docs/why/bet.md","sourceDirName":"why","slug":"/why/bet","permalink":"/why/bet","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":3,"frontMatter":{"sidebar_position":3},"sidebar":"mainSidebar","previous":{"title":"Competitive Landscape","permalink":"/why/market"},"next":{"title":"Signal Flow Overview","permalink":"/how-it-works/overview"}}');var i=n(4848),s=n(8453);const o={sidebar_position:3},r="The Strategic Bet",c={},h=[{value:"Agent cooperation vs. automatic interception",id:"agent-cooperation-vs-automatic-interception",level:2},{value:"Decision provenance beats conversational memory",id:"decision-provenance-beats-conversational-memory",level:2},{value:"Why this matters as agent teams grow",id:"why-this-matters-as-agent-teams-grow",level:2}];function d(e){const t={code:"code",h1:"h1",h2:"h2",header:"header",p:"p",strong:"strong",...(0,s.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.header,{children:(0,i.jsx)(t.h1,{id:"the-strategic-bet",children:"The Strategic Bet"})}),"\n",(0,i.jsx)(t.h2,{id:"agent-cooperation-vs-automatic-interception",children:"Agent cooperation vs. automatic interception"}),"\n",(0,i.jsx)(t.p,{children:"The most obvious approach to agent memory is to intercept sessions automatically \u2014 instrument the agent runtime, capture everything the agent outputs, and extract decisions without requiring the agent to do anything explicit. Some providers are pursuing this. It has appeal: it requires no developer instrumentation, no prompt changes, no compliance tracking."}),"\n",(0,i.jsxs)(t.p,{children:["purpl_brain does not do this. The write-back is cooperative: the agent is expected to call ",(0,i.jsx)(t.code,{children:"brain_log_decision"})," or ",(0,i.jsx)(t.code,{children:"POST /brain/agent-log"})," with a structured decision log. The agent must choose to write, and what it writes must meet quality standards (rationale present, alternatives considered, decisions not just implementation notes)."]}),"\n",(0,i.jsx)(t.p,{children:"The bet is that cooperative write-back produces better data than automatic interception, and that the compliance gap can be closed with tooling rather than by removing developer choice."}),"\n",(0,i.jsx)(t.p,{children:"Here is the reasoning. Automatic capture of session output extracts decisions from raw text generated by an agent that is not thinking about decision structure. The extraction is lossy \u2014 it finds what the agent said, not necessarily what the agent decided, and it cannot recover the alternatives that were considered but not verbalized. A cooperative write-back, where the agent is explicitly prompted to think about what it decided, why, and what alternatives it evaluated, produces structurally richer output. The rationale and alternatives fields are what distinguish a decision log from a session summary, and those fields require the agent's explicit attention."}),"\n",(0,i.jsx)(t.p,{children:"The compliance cost is real. An agent that does not call the write-back tool produces no useful data for that session. The gap between cooperative compliance rates (60-90% depending on setup) and automatic capture (100%) is the price of richer structure. The bet is that 85-90% compliance with high-quality decision logs is more useful than 100% capture of low-quality summaries."}),"\n",(0,i.jsx)(t.h2,{id:"decision-provenance-beats-conversational-memory",children:"Decision provenance beats conversational memory"}),"\n",(0,i.jsx)(t.p,{children:"Most agent memory systems store what agents said. purpl_brain stores what agents decided \u2014 specifically: what was chosen, what was rejected, why the choice was made, how confident the agent was, and what remains unresolved."}),"\n",(0,i.jsx)(t.p,{children:"The difference is not cosmetic. Consider two memory entries for the same session:"}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Conversational memory:"}),' "The agent worked on auth-service and discussed JWT token expiry, considered refresh token rotation, and ultimately made some changes to the token handling code."']}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Decision memory:"}),' "Chose ',(0,i.jsx)(t.code,{children:"node-jsonwebtoken"})," over ",(0,i.jsx)(t.code,{children:"jose"})," because ",(0,i.jsx)(t.code,{children:"jose@5.x"}),' has a JWE incompatibility with the current token format (confidence: high). Rejected refresh token rotation pattern as unnecessary complexity at this stage (confidence: medium). Unresolved: session revocation strategy \u2014 needs decision before merge."']}),"\n",(0,i.jsx)(t.p,{children:"The second entry is what the next agent needs to not re-derive the library choice, not re-evaluate the refresh token pattern, and know exactly what question is waiting for an answer. The first entry tells the next agent that something happened with JWT tokens."}),"\n",(0,i.jsx)(t.p,{children:"This distinction matters more as agent teams scale. A single agent on a single project can rebuild context from session summaries with enough effort. Five agents across three repos, running in parallel, with overnight sessions \u2014 the only thing that prevents contradictions and re-derivation at that scale is structured, queryable memory with explicit alternatives."}),"\n",(0,i.jsx)(t.h2,{id:"why-this-matters-as-agent-teams-grow",children:"Why this matters as agent teams grow"}),"\n",(0,i.jsx)(t.p,{children:"The current state of AI-assisted development is largely one-agent-per-developer, one-session-at-a-time. The trajectory is toward concurrent agents on the same codebase, autonomous overnight runs, and infrastructure agents making schema decisions alongside coding agents making API decisions."}),"\n",(0,i.jsx)(t.p,{children:"At one agent per developer, the re-derivation cost is annoying but manageable. The developer is in the loop and can re-paste context or correct contradictions manually. At five concurrent agents across a codebase, the developer cannot be the human memory bus \u2014 there are too many sessions to supervise, and sessions happen while the developer is offline. The question is not whether there will be contradictions; it is whether there will be a system that detects them before they land in production."}),"\n",(0,i.jsx)(t.p,{children:"The bet that purpl_brain makes is that this shift \u2014 from single-agent development to multi-agent development \u2014 happens within a two-to-three year window, and that the teams that establish shared memory infrastructure now will have a compounding advantage when it does. The brain that has been accumulating decision history for six months is more useful to an agent than an empty brain, and the team that has tuned their write-back compliance is more prepared for multi-agent coordination than the team that has been manually re-pasting context."}),"\n",(0,i.jsx)(t.p,{children:"The strategic position: the memory layer should be built before it is urgently needed, because the cold-start problem is severe. A brain with six months of decisions is a different product than a brain that was just installed. The earlier a team installs and fills it, the more useful it becomes."})]})}function l(e={}){const{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}},8453:(e,t,n)=>{n.d(t,{R:()=>o,x:()=>r});var a=n(6540);const i={},s=a.createContext(i);function o(e){const t=a.useContext(s);return a.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:o(e.components),a.createElement(s.Provider,{value:t},e.children)}}}]);